7	    expect(scale([], 3)).toEqual([]);
8	  });
9	  it("should return identical copy when scale is 1", () => {
10	    expect(scale(["#.", ".#"], 1)).toEqual(["#.", ".#"]);
11	  });
12	  it("should scale single pixel by repeating it horizontally and vertically", () => {
13	    expect(scale(["@"], 4)).toEqual(["@@@@", "@@@@", "@@@@", "@@@@"]);
14	  });
